#define MAX_PLAYERS 3

int main(void) {
    int players[MAX_PLAYERS];
    int playerCount;

    // Read number of players
    scanf("%d", &playerCount);

    if (playerCount > MAX_PLAYERS || playerCount <= 0) {
        printf("Invalid number of players.\n");
        return 1;
    }

    // Initialize players' scores
    for (int i = 0; i < playerCount; i++) {
        players[i] = 0;
    }

    // Simulate tug war rounds
    for (int round = 1; round <= 3; round++) {
        printf("Round %d:\n", round);

        for (int i = 0; i < playerCount; i++) {
            int choice;
            printf("Player %d, Enter: ", i + 1);
            scanf("%d", &choice);

            if (choice != 1 && choice != 2) {
                printf("Invalid input. Player %d chose an invalid option.\n", i + 1);
                return 1;
            }

            players[i]++;
        }

        // Determine winner
        int maxScore = -1;
        int winnerIndex = -1;
        for (int i = 0; i < playerCount; i++) {
            if (players[i] > maxScore) {
                maxScore = players[i];
                winnerIndex = i;
            }
        }

        printf("Winner: Player %d\n", winnerIndex + 1);
    }

    return 0;
}

